		{ title: "Basic Marble Testing", content: "import { TestScheduler } from 'rxjs/testing';\nimport { map } from 'rxjs/operators';\n\ndescribe('Observable tests', () => {\n  let testScheduler: TestScheduler;\n\n  beforeEach(() => {\n    testScheduler = new TestScheduler((actual, expected) => {\n      expect(actual).toEqual(expected);\n    });\n  });\n\n  it('should map values', () => {\n    testScheduler.run(({ cold, expectObservable }) => {\n      const source$ = cold('a-b-c|', { a: 1, b: 2, c: 3 });\n      const expected = '    a-b-c|';\n      const result$ = source$.pipe(map(x => x * 10));\n      \n      expectObservable(result$).toBe(expected, { a: 10, b: 20, c: 30 });\n    });\n  });\n});" },
		{ title: "Testing Async Operations", content: "import { TestScheduler } from 'rxjs/testing';\nimport { delay, map } from 'rxjs/operators';\n\ndescribe('Async operations', () => {\n  let testScheduler: TestScheduler;\n\n  beforeEach(() => {\n    testScheduler = new TestScheduler((actual, expected) => {\n      expect(actual).toEqual(expected);\n    });\n  });\n\n  it('should delay emissions', () => {\n    testScheduler.run(({ cold, expectObservable }) => {\n      const source$ = cold('a-b-c|', { a: 1, b: 2, c: 3 });\n      const expected = '    ---a-b-c|'; // 30ms delay (3 frames)\n      const result$ = source$.pipe(delay(30));\n      \n      expectObservable(result$).toBe(expected, { a: 1, b: 2, c: 3 });\n    });\n  });\n});" }
